import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest cases
  it.todo("empty item list → premium 5 G (only processing fee)");

  // Base premiums for main items (newcomer, 0 years, no prior contract → adds first-insurance 10% per item; we use long-standing 2yr customer second contract? Simplest: just look at base + fee with no modifiers — newcomer with single item has first-insurance. We'll exercise via integration examples)
  // Use unmodified single-item with a long-standing customer's follow-up contract so only base + fee + loyalty/follow-up. Simpler: test base premium math via the integration examples already in the spec.

  // Base premiums via building-block examples (components, base premium only)
  it.todo("2 runes → base premium 50 G (no block)");
  it.todo("3 runes → base premium 60 G (block applies)");
  it.todo("4 runes → base premium 100 G (no block — exactly 3 required)");
  it.todo("7 runes → base premium 175 G (no block — not a multiple-of-3 special case)");

  // Alike components — clarifying question
  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");

  // Modifier scope on multi-item policies — clarifying question
  it.todo("policy: cursed sword + plain amulet → 210 G before further modifiers and fee (cursed surcharge only on cursed item)");

  // Modifier thresholds
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 5 and cursed → both surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("sword with enchantment 4 and cursed → curse surcharge only");

  // Rounding in MHPCO's favor (premium up, payout down)
  it.todo("premium calculation yielding 197.5 G → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → 350 G (rounded down)");

  // Integration examples (premium)
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7), 3 years → premium 160 G");

  // Standard claim reimbursement (no special clauses)
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("damage to a rune (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");

  // High-enchantment claim clause
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Dragon material clause
  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full, then deductible)");

  // Both clauses — 50% rule wins
  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-enchantment then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per item)");

  // Multiple items of the same type
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords → each entry treated as separate damage with its own deductible");
  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero, whole claim rejected");

  // Cap calculation
  it.todo("policy: sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword premium with modifiers 165 G → cap 2000 G (based on unmodified insurance value)");
  it.todo("policy: sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");

  // Cap exhaustion across successive claims
  it.todo("sword (cap 2000 G), first claim 1500 G → payout 1400 G, cap remaining 600 G");
  it.todo("sword (cap 2000 G), second claim 1500 G → payout 600 G, cap remaining 0 G");

  // Edge cases (CLI-level)
  it.todo("quote includes unknown item type → CLI exits non-zero, error to stderr, no results to stdout");
  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero with error");
  it.todo("claim with damage amount -200 → CLI exits non-zero with error");
});

