const PROCESSING_FEE_G = 5;
const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE_G = 60;
const RUNE_UNIT_PRICE_G = 25;

type Scenario = {
  steps: Array<{ op: "quote"; items: unknown[] }>;
};

const basePremiumForRunes = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_PRICE_G : runeCount * RUNE_UNIT_PRICE_G;

const quotePremium = (items: unknown[]): number => {
  const base = basePremiumForRunes(items.length);
  const withFirstInsurance = Math.ceil((base * 11) / 10);
  return withFirstInsurance + PROCESSING_FEE_G;
};

export const runScenario = (scenario: unknown): unknown => {
  const items = (scenario as Scenario).steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};

