  it("newcomer with cursed sword (steel, enchantment 3) → premium 165 G [integration]", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
